// Motor de Cobrança — Filtro Anti-Abuso
const FASES_REGUA = ['pre','mes1','mes2','mes3','mes4','mes5','pos'];
const DESCONTO_POR_FASE = { pre:0, mes1:0, mes2:0, mes3:5, mes4:15, mes5:20, pos:0 };
const CANAIS_POR_FASE = {
  pre:  ['whatsapp'],
  mes1: ['whatsapp','sms'],
  mes2: ['whatsapp','sms','email'],
  mes3: ['whatsapp','sms','email'],
  mes4: ['whatsapp','sms','email','ligacao'],
  mes5: ['whatsapp','sms','email','ligacao'],
  pos:  ['ligacao'],
};
const INTERVALO_DIAS = { pre:7, mes1:5, mes2:4, mes3:3, mes4:2, mes5:1, pos:7 };

const leads = $input.all();
const horaAtual = new Date().getHours();

// Anti-abuse: só processar 8h-20h
if (horaAtual < 8 || horaAtual >= 20) {
  return [{ json: { status: 'fora_horario', leads: [], total: 0 } }];
}

const leadsParaContato = [];

for (const item of leads) {
  const lead = item.json;
  const fase = lead.fase_cobranca || 'mes1';

  // Anti-abuse: verificar se último contato foi recente
  const ultimoContato = lead.ultimo_contato_em ? new Date(lead.ultimo_contato_em) : null;
  const diasSemContato = ultimoContato 
    ? Math.floor((Date.now() - ultimoContato.getTime()) / (1000*60*60*24))
    : 999;

  const intervaloPorFase = INTERVALO_DIAS[fase] || 3;
  if (diasSemContato < intervaloPorFase) continue; // muito recente

  // Fase 'pos' — só manual
  if (fase === 'pos') continue;

  const canal = (CANAIS_POR_FASE[fase] || ['whatsapp'])[0];
  const desconto = DESCONTO_POR_FASE[fase];
  const nome = (lead.nome || '').split(' ')[0];
  const valor = new Intl.NumberFormat('pt-BR', {style:'currency',currency:'BRL'}).format(lead.valor_em_aberto || 0);

  let mensagem = '';
  if (desconto > 0) {
    const valorDesc = (lead.valor_em_aberto || 0) * (1 - desconto/100);
    const vf = new Intl.NumberFormat('pt-BR', {style:'currency',currency:'BRL'}).format(valorDesc);
    mensagem = `Olá ${nome}! Oferta especial: regularize com ${desconto}% de desconto. De ${valor} por apenas ${vf}. Acesse: {{checkout_url}}`;
  } else {
    mensagem = `Olá ${nome}! Sua mensalidade de ${valor} está em aberto há ${lead.dias_atraso} dias. Regularize agora: {{checkout_url}}`;
  }

  const prioridade = ['mes5','mes4'].includes(fase) ? 'urgente' : fase === 'pre' ? 'baixa' : 'normal';

  leadsParaContato.push({
    ...lead,
    canal,
    mensagem,
    desconto,
    prioridade,
    fase,
  });
}

// Ordenar: urgentes primeiro
leadsParaContato.sort((a,b) => {
  const p = {urgente:0, normal:1, baixa:2};
  return p[a.prioridade] - p[b.prioridade] || b.dias_atraso - a.dias_atraso;
});

return leadsParaContato.map(l => ({ json: l }));
